import java.util.HashMap;
import java.util.Map;
import java.util.List;

public int flipTrees(int n, List<Integer> queries) {
    Map<Integer, Boolean> flippedNodes = new HashMap<>();
    for (int query : queries) {
        flippedNodes.put(query, !flippedNodes.getOrDefault(query, false));
        while (query > 1) {
            query /= 2;
            flippedNodes.put(query, !flippedNodes.getOrDefault(query, false));
        }
    }

    int count = 0;
    for (Map.Entry<Integer, Boolean> node : flippedNodes.entrySet()) {
        if (node.getValue()) {
            count++;
        }
    }
    return count;
}
```

